script:
frappe.listview_settings["Aionion Task"] = {
    onload(listview) {
        listview.page.add_inner_button("CRM Leads", () => {
            window.open("/crm/leads", "_blank");
        });
    }
};

frappe.ui.form.on('Aionion Task', {
    product(frm) {
        if (frm.doc.product === "Equity") {
            frm.set_df_property('task_status', 'options', [
                'Not Started',
                'Completed',
            ]);

        } else if (frm.doc.product === "Bonds") {
            frm.set_df_property('task_status', 'options', [
                'Not Started',
                'Completed',
                'In Progress',
                'Qty Not Available',
                'Maturity Bond',
                'Rejected',
                'Cancelled'
            ]);
        } else if (frm.doc.product === "Mutual Funds") {
            frm.set_df_property('task_status', 'options', [
                'Completed',
                'Not Started',
                'In Progress',
                'Rejected',
            ]);
        } else if (frm.doc.product === "Insurance") {
            frm.set_df_property('task_status', 'options', [
                'Not Started',
                'Not Eligible',
                'Not Interested',
                'No Response',
                'Payment Completed',
                'Current Month Prospect',
                'Next Month Prospect',
                'Future Prospect',
                'Call Back',
                'Rejected',
                'Pending',
                'Issued',
                'Proposal Number not available'
            ]);
        } else if (frm.doc.product === "US Subscription") {
            frm.set_df_property('task_status', 'options', [
                'Compeleted',
                'Not Started',
                'Awaiting Feedback'
            ]);
        }
    }
});

frappe.ui.form.on('Aionion Task', {
    refresh(frm) {
        if (!frm.is_new() && frm.doc.product === "Equity" && frm.doc.docstatus == 0) {
            frm.add_custom_button('Start Onboarding', () => {
                let dialog = new frappe.ui.Dialog({
                    title: 'Demat Verification',
                    fields: [
                        {
                            label: 'KYC Link',
                            fieldname: 'kyc_link',
                            fieldtype: 'Data',
                            reqd: 1
                        }
                    ],
                    primary_action_label: 'Initiate KYC',
                    primary_action(values) {
                        frappe.call({
                            method: 'create_demat_verification',
                            args: {
                                lead: frm.doc.lead,
                                task: frm.doc.name,
                                kyc_link: values.kyc_link
                            },
                            callback: function(r) {

                                if (r.message) {
                                    frappe.msgprint({
                                        title: "Success",
                                        indicator: "green",
                                        message: `
                                            Onboarding Initiated.<br><br>
                                            <a href="/app/demat-verification/${r.message}">
                                                Open Demat Verification
                                            </a>
                                        `
                                    });
                                }
                                dialog.hide();
                            }
                        });
                    }
                });
                dialog.show();
            });
        }
    }
});

frappe.ui.form.on('CRM Lead', {
    refresh(frm) {
        if (!frm.is_new() && frm.doc.status!= 'Converted') {
            frm.add_custom_button('Create Task', () => {
                let dialog = new frappe.ui.Dialog({
                    title: 'Task',
                    fields: [
                        {
                            label: 'Aionion Product',
                            fieldname: 'aionion_product',
                            fieldtype: 'Link',
                            options: 'Aionion Product',
                            reqd: 1
                        }
                    ],
                    primary_action_label: 'Create',
                    primary_action(values) {
                        frappe.call({
                            method: 'create_aionion_task',
                            args: {
                                lead: frm.doc.name,
                                aionion_product: values.aionion_product
                            },
                            callback: function(r) {

                                if (r.message) {
                                    frappe.msgprint({
                                        title: "Success",
                                        indicator: "green",
                                        message: `
                                            Task Created.<br><br>
                                            <a href="/app/aionion-task/${r.message}">
                                                Open Task
                                            </a>
                                        `
                                    });
                                }
                                dialog.hide();
                            }
                        });
                    }
                });
                dialog.show();
            });
        }
    }
});

frappe.ui.form.on('CRM Lead', {

    custom_sales_rm: function(frm) {
        frm.set_query('custom_sales_rm', function() {
            return {
                filters: {
                    user_id: frappe.session.user
                }
            };
        });
    },

    refresh: function(frm) {

        // Force query on load
        frm.trigger('custom_sales_rm');

        // Auto set value
        if (!frm.doc.custom_sales_rm) {
            frappe.db.get_value('Employee',
                { user_id: frappe.session.user },
                'name'
            ).then(r => {
                if (r.message) {
                    frm.set_value('custom_sales_rm', r.message.name);
                }
            });
        }

        // Lock field (optional)
        frm.set_df_property('custom_sales_rm', 'read_only', 1);
    }
});

frappe.ui.form.on('CRM Lead', {
    refresh(frm) {
        toggle_insurance_fields(frm);
    },

    custom_entity(frm) {
        toggle_insurance_fields(frm);
    },

    custom_product(frm) {
        toggle_insurance_fields(frm);
    }
});

function toggle_insurance_fields(frm) {
    let show = frm.doc.custom_entity === "Aionion Insurance";

    let fields = [
        "custom_insurance_section",
        "custom_service_rm_section",
        "custom_pan_number",
        "custom_insurance_company",
        "custom_tenure",
        "custom_expiry_date",
        "custom_fresh_port",
        "custom_proposal_number",
        "custom_sum_assured",
        "custom_gross_premium",
        "custom_net_premium",
        "custom_policy_status_section",
        "custom_policy_status",
        "custom_policy_number",
        "custom_mis_status",
        "custom_mis_verified_by",
        "custom_mis_verified_date",
        "custom_insurance_type"
    ];

    fields.forEach(field => {
        frm.toggle_display(field, show);
    });
}

frappe.ui.form.on('US Subscription Record', {
    refresh: function(frm) {
        // Hide payment section when status is Dropped
        toggle_payment_section(frm);

        if (!frm.is_new() && frappe.user.has_role('US Subscription Admin')) {
            // Approve Payment Button
            if (frm.doc.payment_status !== 'Approved') {
                frm.add_custom_button('✅ Approve Payment', function() {
                    frappe.confirm(
                        'Approve payment for ' + frm.doc.client_name + '?',
                        function() {
                            frappe.call({
                                method: 'aionion_custom.aionion_custom.controllers.crm_lead.approve_us_subscription_payment',
                                args: { us_record_name: frm.doc.name },
                                freeze: true,
                                callback: function(r) {
                                    frappe.msgprint({ message: 'Payment Approved!', indicator: 'green' });
                                    frm.reload_doc();
                                }
                            });
                        }
                    );
                }, 'Payment Actions').css({'color': 'white', 'background-color': '#28a745'});
            }
            // Reject Payment Button
            if (frm.doc.payment_status !== 'Rejected') {
                frm.add_custom_button('❌ Reject Payment', function() {
                    frappe.prompt(
                        { label: 'Rejection Reason', fieldtype: 'Small Text', reqd: 1 },
                        function(values) {
                            frappe.call({
                                method: 'aionion_custom.aionion_custom.controllers.crm_lead.reject_us_subscription_payment',
                                args: { us_record_name: frm.doc.name, reason: values.value },
                                freeze: true,
                                callback: function(r) {
                                    frappe.msgprint({ message: 'Payment Rejected!', indicator: 'red' });
                                    frm.reload_doc();
                                }
                            });
                        },
                        'Reject Payment',
                        'Reject'
                    );
                }, 'Payment Actions').css({'color': 'white', 'background-color': '#dc3545'});
            }
        }
        // Show payment status as color indicator
        if (frm.doc.payment_status) {
            const color = frm.doc.payment_status === 'Approved' ? 'green'
                : frm.doc.payment_status === 'Rejected' ? 'red' : 'orange';
            frm.page.set_indicator(frm.doc.payment_status, color);
        }
    },

    us_status: function(frm) {
        toggle_payment_section(frm);
    }
});

function toggle_payment_section(frm) {
    const is_dropped = frm.doc.us_status === 'Dropped';
    const payment_fields = [
        'us_subscription_section',
        'mode_of_payment_new',
        'payment_month',
        'subscription_type_new',
        'currency_new',
        'sub_start_month',
        'sub_start_date',
        'old_subscription_month',
        'lead_source',
        'column_break_us_2',
        'payment_date',
        'client_status_new',
        'quantity_new',
        'amount_paid_us_subs',
        'sub_end_month',
        'sub_end_date'
    ];
    payment_fields.forEach(function(field) {
        frm.set_df_property(field, 'hidden', is_dropped ? 1 : 0);
    });
    frm.refresh_fields();
}

frappe.listview_settings["CRM Lead"] = frappe.listview_settings["CRM Lead"] || {};

const _orig = frappe.listview_settings["CRM Lead"].onload;
frappe.listview_settings["CRM Lead"].onload = function(listview) {
    if (_orig) _orig(listview);

    // Export Button
    listview.page.add_inner_button("⬇ Export CSV", function() {
        frappe.show_alert({message: "Exporting...", indicator: "blue"});
        fetch("/api/method/aionion_custom.api.lead_us_import_export.export_csv", {
            method: "GET",
            headers: {"X-Frappe-CSRF-Token": frappe.csrf_token}
        })
        .then(r => r.blob())
        .then(blob => {
            const a = document.createElement("a");
            a.href = URL.createObjectURL(blob);
            a.download = "lead_us_export.csv";
            a.click();
            frappe.show_alert({message: "✅ Export complete", indicator: "green"});
        })
        .catch(e => frappe.show_alert({message: "❌ Export failed: " + e.message, indicator: "red"}));
    });

    // Import Button
    listview.page.add_inner_button("⬆ Import CSV", function() {
        new frappe.ui.FileUploader({
            restrictions: {allowed_file_types: [".csv"]},
            on_success: function(file) {
                frappe.show_alert({message: "Importing...", indicator: "blue"});
                frappe.call({
                    method: "aionion_custom.api.lead_us_import_export.import_csv",
                    args: {file_url: file.file_url},
                    freeze: true,
                    freeze_message: "Importing records...",
                    callback: function(r) {
                        const res = r.message;
                        const msg = "✅ " + res.success + " imported" + (res.failed.length ? ", ❌ " + res.failed.length + " failed (check Error Log)" : "");
                        frappe.show_alert({message: msg, indicator: res.failed.length ? "orange" : "green"});
                    }
                });
            }
        });
    });
};

frappe.ui.form.on('US Subscription Record', {

    refresh(frm) {
        // Role-based access for Acknowledgment Sent field
        const canEditAck = frappe.user.has_role([
            'US Subscription Admin',
            'US Subscription TL',
            'System Manager'
        ]);
        frm.set_df_property('email_sent', 'read_only', canEditAck ? 0 : 1);

        if (frm.is_new()) {
            frappe.call({
                method: 'frappe.client.get_value',
                args: {
                    doctype: 'Employee',
                    filters: { user_id: frappe.session.user },
                    fieldname: ['name', 'employee_name']
                },
                callback(r) {
                    if (!r.message) return;
                    frm.set_value('sales_done_by', r.message.name);
                    if (!frm.doc.service_rm) {
                        frm.set_value('service_rm', r.message.name);
                    }
                }
            });
        } else {
            if (frm.doc.sales_done_by && !frm.doc.service_rm) {
                frm.set_value('service_rm', frm.doc.sales_done_by);
            }
        }

        if (!frm.doc.assigned_by && frm.doc.lead) {
            frappe.call({
                method: 'frappe.client.get_value',
                args: {
                    doctype: 'CRM Lead',
                    filters: { name: frm.doc.lead },
                    fieldname: 'custom_sales_rm'
                },
                callback(r) {
                    if (r.message && r.message.custom_sales_rm) {
                        frm.set_value('assigned_by', r.message.custom_sales_rm);
                        fetch_emp_details(frm, r.message.custom_sales_rm);
                    }
                }
            });
        }

        if (frm.doc.assigned_by && (!frm.doc.email_address || !frm.doc.emp_phone)) {
            fetch_emp_details(frm, frm.doc.assigned_by);
        }
    },

    assigned_by(frm) {
        if (frm.doc.assigned_by) {
            fetch_emp_details(frm, frm.doc.assigned_by);
        }
    },

    sales_done_by(frm) {
        if (frm.doc.sales_done_by && !frm.doc.service_rm) {
            frm.set_value('service_rm', frm.doc.sales_done_by);
        }
    }

});

function fetch_emp_details(frm, employee) {
    frappe.call({
        method: 'frappe.client.get_value',
        args: {
            doctype: 'Employee',
            filters: { name: employee },
            fieldname: ['employee_name', 'branch', 'user_id']
        },
        callback(r) {
            if (!r.message) return;
            frm.set_value('emp_name', r.message.employee_name);
            frm.set_value('emp_branch', r.message.branch);

            if (r.message.user_id) {
                frm.set_value('email_address', r.message.user_id);

                frappe.call({
                    method: 'frappe.client.get_value',
                    args: {
                        doctype: 'User',
                        filters: { name: r.message.user_id },
                        fieldname: 'mobile_no'
                    },
                    callback(res) {
                        if (res.message && res.message.mobile_no) {
                            frm.set_value('emp_phone', res.message.mobile_no);
                        }
                    }
                });
            }
        }
    });
}

