// ── Poll for incoming/active calls ───────────────────────────────────────────

var _customerCallShownIds = new Set();
var _customerCallPollTimer = null;

function checkForActiveCalls(call) {
	if (_customerCallPollTimer) return;

	function poll() {
		if (document.getElementById('smartflo-call-widget')) return;

		frappe.call({
			method: 'tata_tele_service.tata_tele_service.doctype.tata_tele_settings.tata_tele_settings.get_live_calls',
			args: {},
			callback: function(r) {
				var data = r.message;
				if (!data || !data.agent_number) return;
				var liveCalls = Array.isArray(data.data) ? data.data : [];

				for (var i = 0; i < liveCalls.length; i++) {
					var c = liveCalls[i];
					var cid = c.call_id;
					if (!cid || _customerCallShownIds.has(cid)) continue;
					_customerCallShownIds.add(cid);
					var callerNumber = c.customer_number || c.source || '';
					showCallWidget(callerNumber, null, c, call);
					break;
				}
			}
		});
	}

	_customerCallPollTimer = setInterval(poll, 2500);
	poll();
}

// ── Live Call Widget ──────────────────────────────────────────────────────────

function showCallWidget(destinationNumber, clickToCallResponse, activeCallData, call) {
	var existing = document.getElementById('smartflo-call-widget');
	if (existing) existing.remove();

	var pollTimer = null;
	var tickTimer = null;
	var callId = null;
	var state = 'connecting';

	if (activeCallData) {
		callId = activeCallData.call_id || null;
		var apiState0 = (activeCallData.state || '').toLowerCase();
		if (apiState0.includes('answer') || apiState0.includes('bridge')) {
			state = 'answered';
		} else if (apiState0.includes('ring') || apiState0.includes('dial')) {
			state = 'ringing';
		} else {
			state = 'answered';
		}
	}

	if (!callId && clickToCallResponse && clickToCallResponse.data) {
		var respData = clickToCallResponse.data;
		callId = respData.call_id || respData.callid || respData.id || null;
	}

	var phoneIconSvg = '<svg width="16" height="16" viewBox="0 0 16 16" fill="currentColor"><path fill-rule="evenodd" clip-rule="evenodd" d="M2.67754 2.70675C2.53628 2.84008 2.44787 3.03363 2.46988 3.29885C2.47828 3.40004 2.4869 3.50717 2.49497 3.61981C2.63494 4.75003 2.9076 5.83579 3.29638 6.82863L4.1395 6.29907C5.02533 5.74269 5.45257 4.67951 5.19805 3.66489L4.98918 2.83225C4.93526 2.61729 4.74204 2.46656 4.52043 2.46656H3.36772C3.06265 2.46656 2.82575 2.56686 2.67754 2.70675ZM3.69508 7.71962L4.6536 7.11757C5.89375 6.33864 6.49189 4.85019 6.13556 3.42971L5.9267 2.59708C5.76493 1.9522 5.18528 1.5 4.52043 1.5H3.36772C2.85467 1.5 2.368 1.66981 2.01409 2.00386C1.65323 2.34447 1.46097 2.82869 1.50663 3.3788C1.51521 3.48212 1.52381 3.58915 1.53174 3.70087L1.53262 3.71327L1.53414 3.72561C1.70903 5.14795 2.08181 6.51379 2.62992 7.73832C2.8107 8.1422 3.76654 10.0804 5.03876 11.2498C6.27205 12.3833 6.85696 12.7556 8.29758 13.4488L8.31072 13.4551L8.32421 13.4606C9.77742 14.0548 11.0901 14.3742 12.5272 14.4965C13.6361 14.5909 14.4998 13.677 14.4998 12.6231V11.5096C14.4998 10.8539 14.0598 10.2799 13.4267 10.1095L12.6539 9.90153C11.1864 9.50659 9.63455 10.1384 8.86371 11.4495C8.67966 11.7625 8.49178 12.0826 8.3163 12.3822C7.24188 11.8473 6.72935 11.4908 5.69284 10.5382C4.79599 9.71382 4.04577 8.4042 3.69508 7.71962ZM9.21019 12.7685C10.3726 13.198 11.4466 13.4344 12.6092 13.5334C13.096 13.5749 13.5332 13.1706 13.5332 12.6231V11.5096C13.5332 11.291 13.3866 11.0997 13.1755 11.0429L12.4027 10.8349C11.3541 10.5527 10.2467 11.0044 9.69692 11.9394C9.53381 12.2168 9.3678 12.4995 9.21019 12.7685Z"/></svg>';

	if (!document.getElementById('smartflo-call-styles')) {
		var styleEl = document.createElement('style');
		styleEl.id = 'smartflo-call-styles';
		styleEl.textContent = '@keyframes cw-enter{from{opacity:0;transform:translateY(8px) scale(0.97)}}'
			+ '@keyframes cw-pulse{0%,100%{opacity:1}50%{opacity:0.35}}'
			+ '@keyframes cw-blink{0%,100%{opacity:1}50%{opacity:0}}'
			+ '.cw-enter{animation:cw-enter 0.35s cubic-bezier(0.16,1,0.3,1) both}'
			+ '.cw-pulse{animation:cw-pulse 2s ease-in-out infinite}'
			+ '.cw-blink{animation:cw-blink 1s ease-in-out 6}'
			+ '.cw-hangup-icon{transform:rotate(135deg)}'
			+ '#smartflo-call-widget *{box-sizing:border-box}'
			+ '#smartflo-expanded{background:#2c2c2c;border-radius:10px;padding:10px 14px 14px;width:280px;box-shadow:0 8px 32px rgba(0,0,0,0.4);color:#ccc;font-family:inherit}'
